  "requestFramePermissions": [
    "geolocation"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface JourneyInfo {
  origin: string;
  destination: string;
  distance: string;
  duration: string;
  departureTime: string;
  arrivalTime: string;
  weatherAtArrival: {
    temp: string;
    condition: string;
    description: string;
    icon: string;
  };
  sources: Array<{ title: string; uri: string }>;
}

export interface SearchParams {
  origin: string;
  destination: string;
  departureTime: string;
}

export enum AppStatus {
  IDLE = 'IDLE',
  LOADING = 'LOADING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR'
}

import { GoogleGenAI } from "@google/genai";
import { SearchParams, JourneyInfo } from "../types";

const API_KEY = process.env.API_KEY || "";

export const getTravelData = async (params: SearchParams): Promise<JourneyInfo> => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  // We use gemini-2.5-flash because it supports googleMaps grounding
  const model = "gemini-2.5-flash";

  const prompt = `
    Agisci come un esperto di viaggi in Calabria, Italia.
    L'utente vuole viaggiare da "${params.origin}" a "${params.destination}" partendo alle ore ${params.departureTime}.

    Esegui le seguenti operazioni:
    1. Usa Google Maps per trovare la distanza esatta in automobile e la durata stimata del viaggio tra queste due località in Calabria.
    2. Calcola l'orario di arrivo stimato sommando la durata alla partenza (${params.departureTime}).
    3. Usa Google Search o la tua conoscenza aggiornata per prevedere le condizioni meteo a ${params.destination} per l'orario di arrivo stimato.

    Restituisci i dati in un formato JSON strutturato come segue:
    {
      "origin": "Città di partenza",
      "destination": "Città di arrivo",
      "distance": "distanza in km (es: 150 km)",
      "duration": "durata (es: 1h 45m)",
      "departureTime": "${params.departureTime}",
      "arrivalTime": "orario calcolato",
      "weatherAtArrival": {
        "temp": "temperatura stimata (es: 22°C)",
        "condition": "Soleggiato/Nuvoloso/Pioggia",
        "description": "Breve descrizione del meteo",
        "icon": "un nome di icona FontAwesome appropriato (es: fa-sun, fa-cloud-sun, fa-cloud-showers-heavy)"
      }
    }

    Assicurati che i luoghi siano all'interno della regione Calabria. Se uno dei luoghi non è in Calabria, segnalalo nel campo description.
  `;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: prompt,
      config: {
        tools: [{ googleMaps: {} }, { googleSearch: {} }],
        responseMimeType: "application/json"
      },
    });

    const resultText = response.text || "";
    const parsedData = JSON.parse(resultText);

    // Extract sources from grounding metadata if available
    const sources: Array<{title: string, uri: string}> = [];
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (groundingChunks) {
      groundingChunks.forEach((chunk: any) => {
        if (chunk.maps) {
          sources.push({ title: chunk.maps.title || "Mappa Calabria", uri: chunk.maps.uri });
        } else if (chunk.web) {
          sources.push({ title: chunk.web.title || "Ricerca Meteo", uri: chunk.web.uri });
        }
      });
    }

    return {
      ...parsedData,
      sources: sources
    };
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Errore durante il calcolo del viaggio. Riprova tra poco.");
  }
};

