import { GoogleGenAI } from "@google/genai";
import { SearchParams, JourneyInfo } from "../types";

export const getTravelData = async (params: SearchParams, userCoords?: { lat: number; lng: number }): Promise<JourneyInfo> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Maps grounding richiede modelli della serie Gemini 2.5
  const model = "gemini-2.5-flash";

  const prompt = `
    Agisci come un esperto di viaggi e logistica in Calabria, Italia.
    Pianifica un viaggio in auto da "${params.origin}" a "${params.destination}" con partenza alle ore ${params.departureTime}.

    REGOLE RIGIDE:
    1. Entrambe le località DEVONO essere in Calabria. Se non lo sono, segnalalo nel campo description.
    2. Usa Google Maps per trovare la distanza esatta e la durata del viaggio.
    3. Calcola l'orario di arrivo stimato.
    4. Usa Google Search per le previsioni meteo a ${params.destination} per l'orario di arrivo.

    RESTITUISCI SOLO UN OGGETTO JSON puro, senza blocchi di codice markdown, con questa struttura:
    {
      "origin": "Città di partenza",
      "destination": "Città di arrivo",
      "distance": "es: 120 km",
      "duration": "es: 1h 30m",
      "departureTime": "${params.departureTime}",
      "arrivalTime": "HH:MM",
      "weatherAtArrival": {
        "temp": "es: 24°C",
        "condition": "Soleggiato",
        "description": "Breve descrizione",
        "icon": "icona FontAwesome (es: fa-sun, fa-cloud-sun, fa-cloud-rain)"
      }
    }
  `;

  try {
    const config: any = {
      tools: [{ googleMaps: {} }, { googleSearch: {} }]
    };

    // Se abbiamo le coordinate, le passiamo per migliorare il grounding
    if (userCoords) {
      config.toolConfig = {
        retrievalConfig: {
          latLng: {
            latitude: userCoords.lat,
            longitude: userCoords.lng
          }
        }
      };
    }

    const response = await ai.models.generateContent({
      model: model,
      contents: prompt,
      config: config,
    });

    const resultText = response.text || "";
    // Pulizia del testo per estrarre solo il JSON (nel caso il modello aggiunga commenti)
    const jsonMatch = resultText.match(/\{[\s\S]*\}/);
    const jsonStr = jsonMatch ? jsonMatch[0] : resultText;
    const parsedData = JSON.parse(jsonStr);

    const sources: Array<{title: string, uri: string}> = [];
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (groundingChunks) {
      groundingChunks.forEach((chunk: any) => {
        if (chunk.maps) {
          sources.push({ title: chunk.maps.title || "Percorso Mappe", uri: chunk.maps.uri });
        } else if (chunk.web) {
          sources.push({ title: chunk.web.title || "Meteo Località", uri: chunk.web.uri });
        }
      });
    }

    return {
      ...parsedData,
      sources: sources
    };
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw new Error("Errore nella comunicazione con il servizio. Verifica che le località siano in Calabria.");
  }
};

import React, { useState } from 'react';
import { SearchParams } from '../types';

interface JourneyFormProps {
  onSubmit: (params: SearchParams, coords?: { lat: number; lng: number }) => void;
  loading: boolean;
}

const calabriaCities = [
  "Catanzaro", "Reggio Calabria", "Cosenza", "Crotone", "Vibo Valentia",
  "Lamezia Terme", "Corigliano-Rossano", "Rende", "Castrovillari", "Acri",
  "Palmi", "Siderno", "Gioia Tauro", "Tropea", "Scilla", "Soverato", "Villa San Giovanni"
];

const JourneyForm: React.FC<JourneyFormProps> = ({ onSubmit, loading }) => {
  const [origin, setOrigin] = useState('');
  const [destination, setDestination] = useState('');
  const [departureTime, setDepartureTime] = useState(
    new Date().toLocaleTimeString('it-IT', { hour: '2-digit', minute: '2-digit' })
  );
  const [locating, setLocating] = useState(false);
  const [userCoords, setUserCoords] = useState<{ lat: number; lng: number } | undefined>();

  const handleGetLocation = () => {
    if (!navigator.geolocation) return;
    setLocating(true);
    navigator.geolocation.getCurrentPosition(
      (pos) => {
        const coords = { lat: pos.coords.latitude, lng: pos.coords.longitude };
        setUserCoords(coords);
        setOrigin("La mia posizione attuale");
        setLocating(false);
      },
      () => {
        setLocating(false);
        alert("Impossibile ottenere la posizione attuale.");
      }
    );
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (origin && destination) {
      onSubmit({ origin, destination, departureTime }, userCoords);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="bg-white p-6 rounded-2xl shadow-xl border border-gray-100 max-w-2xl mx-auto -mt-12 relative z-10">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
        <div className="space-y-2">
          <label className="block text-sm font-semibold text-gray-700 flex justify-between">
            Partenza
            <button 
              type="button" 
              onClick={handleGetLocation}
              className="text-blue-600 text-xs hover:underline flex items-center gap-1"
            >
              <i className={`fa-solid ${locating ? 'fa-spinner animate-spin' : 'fa-location-crosshairs'}`}></i>
              Usa la mia posizione
            </button>
          </label>
          <div className="relative">
            <span className="absolute inset-y-0 left-0 pl-3 flex items-center text-gray-400">
              <i className="fa-solid fa-location-dot"></i>
            </span>
            <input
              list="cities-list"
              type="text"
              className="block w-full pl-10 pr-3 py-3 border border-gray-300 rounded-xl focus:ring-blue-500 focus:border-blue-500 text-gray-900 transition-all"
              placeholder="Es: Catanzaro"
              value={origin}
              onChange={(e) => {
                setOrigin(e.target.value);
                if (userCoords) setUserCoords(undefined);
              }}
              required
            />
          </div>
        </div>

        <div className="space-y-2">
          <label className="block text-sm font-semibold text-gray-700">Arrivo (Calabria)</label>
          <div className="relative">
            <span className="absolute inset-y-0 left-0 pl-3 flex items-center text-gray-400">
              <i className="fa-solid fa-flag-checkered"></i>
            </span>
            <input
              list="cities-list"
              type="text"
              className="block w-full pl-10 pr-3 py-3 border border-gray-300 rounded-xl focus:ring-blue-500 focus:border-blue-500 text-gray-900 transition-all"
              placeholder="Es: Scilla"
              value={destination}
              onChange={(e) => setDestination(e.target.value)}
              required
            />
          </div>
        </div>
      </div>

      <div className="flex flex-col md:flex-row md:items-end gap-6">
        <div className="flex-1 space-y-2">
          <label className="block text-sm font-semibold text-gray-700">Orario di Partenza</label>
          <input
            type="time"
            className="block w-full px-3 py-3 border border-gray-300 rounded-xl focus:ring-blue-500 focus:border-blue-500 text-gray-900"
            value={departureTime}
            onChange={(e) => setDepartureTime(e.target.value)}
            required
          />
        </div>

        <button
          type="submit"
          disabled={loading}
          className={`flex-[2] py-3 px-6 rounded-xl font-bold text-white transition-all shadow-md flex items-center justify-center gap-2 ${
            loading ? 'bg-gray-400 cursor-not-allowed' : 'bg-blue-600 hover:bg-blue-700 active:scale-95'
          }`}
        >
          {loading ? (
            <><i className="fa-solid fa-circle-notch animate-spin"></i> Analisi in corso...</>
          ) : (
            <><i className="fa-solid fa-route"></i> Calcola Viaggio</>
          )}
        </button>
      </div>

      <datalist id="cities-list">
        {calabriaCities.map(city => <option key={city} value={city} />)}
      </datalist>
    </form>
  );
};

export default JourneyForm;

