import { GoogleGenAI } from "@google/genai";
import { SearchParams, JourneyInfo } from "../types";

export const getTravelData = async (params: SearchParams, userCoords?: { lat: number; lng: number }): Promise<JourneyInfo> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Utilizziamo gemini-2.5-flash per il supporto obbligatorio a Google Maps Grounding
  const model = "gemini-2.5-flash";

  const prompt = `
    Sei un assistente di viaggio specializzato esclusivamente nella regione Calabria, Italia.
    Analizza un viaggio in auto da "${params.origin}" a "${params.destination}" partendo alle ore ${params.departureTime}.

    COMPITI:
    1. Verifica che PARTENZA e ARRIVO siano in Calabria. Se una delle due località è fuori dalla regione, scrivi "LOCALITÀ_NON_CALABRESE" nel campo 'description' del JSON e indica quale.
    2. Usa lo strumento Google Maps per calcolare la distanza esatta in chilometri e la durata stimata del viaggio.
    3. Calcola l'orario di arrivo esatto sommando la durata alla partenza.
    4. Usa Google Search per trovare le previsioni meteo a ${params.destination} per l'orario di arrivo calcolato.

    RISPONDI ESCLUSIVAMENTE con un oggetto JSON valido. Non aggiungere testo prima o dopo.
    Struttura richiesta:
    {
      "origin": "Nome località partenza",
      "destination": "Nome località arrivo",
      "distance": "es: 105 km",
      "duration": "es: 1 ora e 20 min",
      "departureTime": "${params.departureTime}",
      "arrivalTime": "HH:MM",
      "weatherAtArrival": {
        "temp": "es: 18°C",
        "condition": "Soleggiato",
        "description": "Descrizione dettagliata meteo",
        "icon": "icona FontAwesome (es: fa-sun, fa-cloud-sun, fa-cloud-rain, fa-wind)"
      }
    }
  `;

  try {
    const config: any = {
      tools: [{ googleMaps: {} }, { googleSearch: {} }],
      // Note: non impostiamo responseMimeType perché non compatibile con googleMaps tool
    };

    if (userCoords) {
      config.toolConfig = {
        retrievalConfig: {
          latLng: {
            latitude: userCoords.lat,
            longitude: userCoords.lng
          }
        }
      };
    }

    const response = await ai.models.generateContent({
      model: model,
      contents: prompt,
      config: config,
    });

    const resultText = response.text || "";

    // Pulizia robusta: estrae il contenuto tra le parentesi graffe più esterne
    // per evitare errori se il modello include tag markdown ```json ... ```
    const firstBrace = resultText.indexOf('{');
    const lastBrace = resultText.lastIndexOf('}');

    if (firstBrace === -1 || lastBrace === -1) {
      throw new Error("Il modello non ha restituito un formato dati valido.");
    }

    const jsonStr = resultText.substring(firstBrace, lastBrace + 1);
    const parsedData = JSON.parse(jsonStr);

    // Gestione caso località fuori Calabria gestito via prompt
    if (parsedData.description?.includes("LOCALITÀ_NON_CALABRESE")) {
      throw new Error(`Spiacente, questa applicazione supporta solo spostamenti all'interno della Calabria. ${parsedData.description}`);
    }

    const sources: Array<{title: string, uri: string}> = [];
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (groundingChunks) {
      groundingChunks.forEach((chunk: any) => {
        if (chunk.maps) {
          sources.push({ title: chunk.maps.title || "Percorso Mappe", uri: chunk.maps.uri });
        } else if (chunk.web) {
          sources.push({ title: chunk.web.title || "Meteo Grounding", uri: chunk.web.uri });
        }
      });
    }

    return {
      ...parsedData,
      sources: sources
    };
  } catch (error: any) {
    console.error("Gemini API/Parsing Error:", error);
    if (error instanceof SyntaxError) {
      throw new Error("Errore nel formato dei dati ricevuti. Riprova con nomi di città più precisi.");
    }
    throw new Error(error.message || "Impossibile calcolare il viaggio. Verifica la connessione e i nomi delle località.");
  }
};

