import { GoogleGenAI } from "@google/genai";
import { SearchParams, JourneyInfo } from "../types";

export const getTravelData = async (params: SearchParams, userCoords?: { lat: number; lng: number }): Promise<JourneyInfo> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Utilizziamo gemini-2.5-flash per il supporto obbligatorio a Google Maps Grounding
  const model = "gemini-2.5-flash";

  const prompt = `
    AGISCI COME UN'API DI SISTEMA. 
    DESTINAZIONE: CALABRIA, ITALIA.
    UTENTE: Viaggio da "${params.origin}" a "${params.destination}" alle ${params.departureTime}.

    OPERAZIONI OBBLIGATORIE:
    1. Usa Google Maps Grounding per ottenere distanza (km) e durata (min/ore).
    2. Calcola l'orario di arrivo.
    3. Usa Google Search Grounding per il meteo a "${params.destination}" all'arrivo.

    FORMATO DI RISPOSTA:
    Restituisci ESCLUSIVAMENTE un oggetto JSON. Non aggiungere introduzioni, spiegazioni o blocchi di codice markdown. Se i luoghi non sono in Calabria, compila comunque ma aggiungi una nota nel campo description.

    STRUTTURA JSON:
    {
      "origin": "string",
      "destination": "string",
      "distance": "string (es. 120 km)",
      "duration": "string (es. 1h 45m)",
      "departureTime": "${params.departureTime}",
      "arrivalTime": "string (HH:MM)",
      "weatherAtArrival": {
        "temp": "string",
        "condition": "string",
        "description": "string",
        "icon": "icona FontAwesome (fa-sun, fa-cloud, fa-cloud-showers-heavy)"
      }
    }
  `;

  try {
    const config: any = {
      tools: [{ googleMaps: {} }, { googleSearch: {} }],
      // Nota: responseMimeType NON è supportato quando si usa googleMaps
    };

    if (userCoords) {
      config.toolConfig = {
        retrievalConfig: {
          latLng: {
            latitude: userCoords.lat,
            longitude: userCoords.lng
          }
        }
      };
    }

    const response = await ai.models.generateContent({
      model: model,
      contents: prompt,
      config: config,
    });

    const resultText = response.text || "";

    // LOGICA DI PARSING ROBUSTA
    // 1. Cerchiamo la prima '{' e l'ultima '}'
    const firstBrace = resultText.indexOf('{');
    const lastBrace = resultText.lastIndexOf('}');

    if (firstBrace === -1 || lastBrace === -1) {
      console.error("Testo ricevuto senza JSON:", resultText);
      throw new Error("Il servizio ha restituito una risposta testuale invece che dati strutturati. Riprova con nomi di città più semplici.");
    }

    let jsonStr = resultText.substring(firstBrace, lastBrace + 1);

    // 2. Pulizia da eventuali residui di markdown o commenti
    jsonStr = jsonStr.replace(/```json/g, "").replace(/```/g, "").trim();

    let parsedData;
    try {
      parsedData = JSON.parse(jsonStr);
    } catch (parseErr) {
      console.error("Errore parsing JSON:", jsonStr);
      throw new Error("Errore nel processare i dati del viaggio. Riprova tra un istante.");
    }

    const sources: Array<{title: string, uri: string}> = [];
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (groundingChunks) {
      groundingChunks.forEach((chunk: any) => {
        if (chunk.maps) {
          sources.push({ title: chunk.maps.title || "Dati Percorso", uri: chunk.maps.uri });
        } else if (chunk.web) {
          sources.push({ title: chunk.web.title || "Dati Meteo", uri: chunk.web.uri });
        }
      });
    }

    return {
      ...parsedData,
      sources: sources
    };
  } catch (error: any) {
    console.error("Gemini Service Error:", error);
    throw new Error(error.message || "Impossibile calcolare il viaggio. Verifica che le località siano corrette.");
  }
};

