import { GoogleGenAI } from "@google/genai";
import { SearchParams, JourneyInfo } from "../types";

export const getTravelData = async (params: SearchParams, userCoords?: { lat: number; lng: number }): Promise<JourneyInfo> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Utilizziamo gemini-2.5-flash per il supporto obbligatorio a Google Maps Grounding
  const model = "gemini-2.5-flash";

  const prompt = `
    AGISCI COME UN'API DI SISTEMA. 
    DESTINAZIONE: REGIONE CALABRIA, ITALIA.
    UTENTE: Viaggio da "${params.origin}" a "${params.destination}" alle ${params.departureTime}.

    NOTE SUI LUOGHI:
    I nomi potrebbero essere nel formato "Città (Provincia)". Ignora la provincia tra parentesi per la ricerca ma usala per contestualizzare il luogo in Calabria.

    OPERAZIONI OBBLIGATORIE:
    1. Usa Google Maps Grounding per ottenere distanza (km) e durata (min/ore).
    2. Calcola l'orario di arrivo esatto aggiungendo la durata all'orario di partenza.
    3. Usa Google Search Grounding per il meteo a "${params.destination}" specifico per l'orario di arrivo.

    FORMATO DI RISPOSTA:
    Restituisci ESCLUSIVAMENTE un oggetto JSON. Non aggiungere introduzioni o spiegazioni. Se i luoghi non sono in Calabria, compila comunque ma aggiungi "ATTENZIONE: Luogo fuori regione" nel campo description.

    STRUTTURA JSON:
    {
      "origin": "string",
      "destination": "string",
      "distance": "string (es. 120 km)",
      "duration": "string (es. 1h 45m)",
      "departureTime": "${params.departureTime}",
      "arrivalTime": "string (HH:MM)",
      "weatherAtArrival": {
        "temp": "string",
        "condition": "string",
        "description": "string",
        "icon": "icona FontAwesome (es. fa-sun, fa-cloud, fa-cloud-showers-heavy, fa-wind)"
      }
    }
  `;

  try {
    const config: any = {
      tools: [{ googleMaps: {} }, { googleSearch: {} }],
    };

    if (userCoords) {
      config.toolConfig = {
        retrievalConfig: {
          latLng: {
            latitude: userCoords.lat,
            longitude: userCoords.lng
          }
        }
      };
    }

    const response = await ai.models.generateContent({
      model: model,
      contents: prompt,
      config: config,
    });

    const resultText = response.text || "";

    // Parsing JSON robusto
    const firstBrace = resultText.indexOf('{');
    const lastBrace = resultText.lastIndexOf('}');

    if (firstBrace === -1 || lastBrace === -1) {
      throw new Error("Il servizio ha restituito dati non validi. Prova a inserire i nomi manualmente senza sigle.");
    }

    let jsonStr = resultText.substring(firstBrace, lastBrace + 1);
    jsonStr = jsonStr.replace(/```json/g, "").replace(/```/g, "").trim();

    let parsedData;
    try {
      parsedData = JSON.parse(jsonStr);
    } catch (parseErr) {
      throw new Error("Errore nell'elaborazione dei dati del viaggio.");
    }

    const sources: Array<{title: string, uri: string}> = [];
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (groundingChunks) {
      groundingChunks.forEach((chunk: any) => {
        if (chunk.maps) {
          sources.push({ title: chunk.maps.title || "Percorso Mappe", uri: chunk.maps.uri });
        } else if (chunk.web) {
          sources.push({ title: chunk.web.title || "Dati Meteo", uri: chunk.web.uri });
        }
      });
    }

    return {
      ...parsedData,
      sources: sources
    };
  } catch (error: any) {
    console.error("Gemini Service Error:", error);
    throw new Error(error.message || "Impossibile calcolare il viaggio. Controlla i nomi dei comuni.");
  }
};

