  try {
    const config: any = {
      systemInstruction: systemInstruction,
      tools: [{ googleMaps: {} }, { googleSearch: {} }],
    };

    if (userCoords) {
      config.toolConfig = {
        retrievalConfig: {
          latLng: {
            latitude: userCoords.lat,
            longitude: userCoords.lng
          }
        }
      };
    }

    const response = await ai.models.generateContent({
      model: modelName,
      contents: userPrompt,
      config: config,
    });

    let resultText = response.text || "";

    // Logica di recupero JSON ultra-robusta
    // Rimuove eventuali blocchi ```json ... ``` o testo circostante
    resultText = resultText.replace(/```json/g, "").replace(/```/g, "");

    const firstBrace = resultText.indexOf('{');
    const lastBrace = resultText.lastIndexOf('}');

    if (firstBrace === -1 || lastBrace === -1) {
      console.error("Risposta grezza del modello:", resultText);
      throw new Error("Il modello non ha restituito un formato dati valido. Riprova tra un istante.");
    }

    const jsonStr = resultText.substring(firstBrace, lastBrace + 1).trim();

    let parsedData: any;
    try {
      parsedData = JSON.parse(jsonStr);
    } catch (parseErr) {
      console.error("Errore parsing JSON su stringa:", jsonStr);
      throw new Error("Errore nella struttura dei dati ricevuti. Riprova con nomi di città più semplici.");
    }

