    // Rimuoviamo duplicati dalle fonti
    const uniqueSources = Array.from(new Map(sources.map(s => [s.uri, s])).values());

    return {
      ...parsedData,
      sources: uniqueSources
    };
  } catch (error: any) {
    console.error("Gemini Service Error:", error);
    if (error.message?.includes("parsing")) {
        throw new Error("Errore di comunicazione con il servizio meteo/mappe. Riprova.");
    }
    throw new Error(error.message || "Impossibile calcolare il viaggio. Verifica la connessione.");
