  "destination": "string",
  "distance": "string (es. 95 km)",
  "duration": "string (es. 1h 10m)",
  "departureTime": "string",
  "arrivalTime": "string (HH:MM)",
  "weatherAtArrival": {
    "temp": "string",
    "condition": "string",
    "description": "string",
    "icon": "string (icona FontAwesome)"
