    new Date().toLocaleTimeString('it-IT', { hour: '2-digit', minute: '2-digit' })
  );
  const [locating, setLocating] = useState(false);
  const [userCoords, setUserCoords] = useState<{ lat: number; lng: number } | undefined>();

  // Flattening e ordinamento della lista dei comuni per il datalist
  const flattenedCities = useMemo(() => {
    const list: string[] = [];
    Object.entries(CALABRIA_DATA).forEach(([province, cities]) => {
      cities.forEach(city => {
        list.push(`${city} (${province.split(' ')[0]})`);
      });
    });
    return list.sort();
  }, []);

  const handleGetLocation = () => {
    if (!navigator.geolocation) return;
    setLocating(true);
    navigator.geolocation.getCurrentPosition(
      (pos) => {
        const coords = { lat: pos.coords.latitude, lng: pos.coords.longitude };
        setUserCoords(coords);
        setOrigin("Posizione attuale");
        setLocating(false);
      },
      (err) => {
        setLocating(false);
        alert("Permesso di posizione negato o errore GPS.");
      },
      { enableHighAccuracy: true, timeout: 5000 }
    );
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const cleanOrigin = origin.trim();
    const cleanDestination = destination.trim();

    if (!cleanOrigin || !cleanDestination) return;

    onSubmit({ origin: cleanOrigin, destination: cleanDestination, departureTime }, userCoords);
  };

  return (
    <form onSubmit={handleSubmit} className="bg-white p-6 rounded-2xl shadow-xl border border-gray-100 max-w-2xl mx-auto -mt-12 relative z-10">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
        <div className="space-y-2">
          <div className="flex justify-between items-center">
            <label className="text-sm font-semibold text-gray-700">Punto di Partenza</label>
            <button 
              type="button" 
              onClick={handleGetLocation}
              disabled={loading}
              className={`text-[10px] font-bold flex items-center gap-1 px-2 py-1 rounded-md transition-colors ${
                userCoords ? 'bg-emerald-100 text-emerald-700' : 'text-blue-600 hover:bg-blue-50'
              }`}
            >
              <i className={`fa-solid ${locating ? 'fa-spinner animate-spin' : userCoords ? 'fa-check-circle' : 'fa-location-crosshairs'}`}></i>
              {userCoords ? 'POSIZIONE ACQUISITA' : 'USA MIA POSIZIONE'}
            </button>
          </div>
          <div className="relative">
            <span className="absolute inset-y-0 left-0 pl-3 flex items-center text-gray-400">
              <i className="fa-solid fa-location-dot"></i>
            </span>
            <input
              list="cities-list"
              type="text"
              className="block w-full pl-10 pr-3 py-3 border border-gray-300 rounded-xl focus:ring-blue-500 focus:border-blue-500 text-gray-900 transition-all outline-none"
              placeholder="Città (es. Catanzaro)"
              value={origin}
              onChange={(e) => {
                setOrigin(e.target.value);
                if (userCoords && e.target.value !== "Posizione attuale") setUserCoords(undefined);
              }}
              required
            />
          </div>
        </div>

        <div className="space-y-2">
          <label className="block text-sm font-semibold text-gray-700">Destinazione</label>
          <div className="relative">
            <span className="absolute inset-y-0 left-0 pl-3 flex items-center text-gray-400">
              <i className="fa-solid fa-flag-checkered"></i>
            </span>
            <input
              list="cities-list"
              type="text"
              className="block w-full pl-10 pr-3 py-3 border border-gray-300 rounded-xl focus:ring-blue-500 focus:border-blue-500 text-gray-900 transition-all outline-none"
              placeholder="Destinazione in Calabria"
              value={destination}
              onChange={(e) => setDestination(e.target.value)}
              required
            />
          </div>
        </div>
      </div>

      <div className="flex flex-col md:flex-row md:items-end gap-6">
        <div className="flex-1 space-y-2">
          <label className="block text-sm font-semibold text-gray-700">Orario Partenza</label>
          <input
            type="time"
            className="block w-full px-3 py-3 border border-gray-300 rounded-xl focus:ring-blue-500 focus:border-blue-500 text-gray-900 outline-none"
            value={departureTime}
            onChange={(e) => setDepartureTime(e.target.value)}
            required
          />
        </div>

        <button
          type="submit"
          disabled={loading}
          className={`flex-[2] py-3 px-6 rounded-xl font-bold text-white transition-all shadow-lg flex items-center justify-center gap-2 ${
            loading ? 'bg-gray-400 cursor-not-allowed' : 'bg-gradient-to-r from-blue-600 to-blue-700 hover:from-blue-700 hover:to-blue-800 active:scale-[0.98]'
          }`}
        >
          {loading ? (
            <><i className="fa-solid fa-satellite-dish animate-pulse"></i> Recupero dati...</>
          ) : (
            <><i className="fa-solid fa-route"></i> Calcola Ora</>
          )}
        </button>
      </div>

      <datalist id="cities-list">
        {flattenedCities.map(city => <option key={city} value={city} />)}
      </datalist>
    </form>
  );
};

