import { GoogleGenAI } from "@google/genai";
import { SearchParams, JourneyInfo } from "../types";

export const getTravelData = async (params: SearchParams, userCoords?: { lat: number; lng: number }): Promise<JourneyInfo> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const modelName = "gemini-3-pro-preview";

  const systemInstruction = `Sei un assistente esperto di logistica e trasporti per la regione Calabria.
Il tuo compito è fornire dati precisi su viaggi tra comuni calabresi.
DEVI RESTITUIRE ESCLUSIVAMENTE UN OGGETTO JSON.

REGOLE CRITICHE:
1. PRECISIONE GEOGRAFICA: Assicurati di non confondere le province. Esempio: "Altilia Grimaldi" si trova in provincia di Cosenza (CS), non Crotone. Verifica sempre l'esatta ubicazione del comune prima di calcolare distanze o meteo.
2. NOMI LOCALITÀ: I campi "origin" e "destination" devono contenere SOLO il nome del comune pulito (es. "Cosenza"). Rimuovi sigle di province o note tra parentesi.
3. DISTANZA/DURATA AUTO: Fornisci una stima basata sulla viabilità reale calabrese (es. Autostrada A2, Statale 106).
4. METEO: Trova le previsioni per la destinazione all'orario di arrivo stimato.
5. TRENI: 
   - Identifica la stazione ferroviaria più vicina all'origine (es. per Altilia Grimaldi verifica stazioni vicine come Rogliano o Cosenza se necessario).
   - Fornisci una lista di opzioni orarie intorno alle ${params.departureTime}, includendo treni fino a 60 min prima.
6. FORMATO: Restituisci SOLO il JSON senza markdown o commenti.

STRUTTURA JSON:
{
  "origin": "string",
  "destination": "string",
  "distance": "string",
  "duration": "string",
  "departureTime": "string",
  "arrivalTime": "string (HH:MM)",
  "weatherAtArrival": {
    "temp": "string",
    "condition": "string",
    "description": "string",
    "icon": "string (es. fa-sun, fa-cloud-rain)"
  },
  "trainAlternative": {
    "available": boolean,
    "departureStation": "string",
    "arrivalStation": "string",
    "options": [
      { "departureTime": "HH:MM", "arrivalTime": "HH:MM", "duration": "string", "changes": number }
    ],
    "description": "string",
    "note": "string"
  }
}`;

  const userPrompt = `Calcola viaggio in Calabria: da "${params.origin}" a "${params.destination}" partendo alle ${params.departureTime}. 
  Nota bene: se una località è indicata con la provincia (es. Altilia Grimaldi (CS)), usala per essere estremamente preciso nella ricerca. 
  Trova tramite ricerca web: distanza stradale reale, meteo previsto all'arrivo e opzioni ferroviarie (stazione di partenza più vicina e orari).`;

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: userPrompt,
      config: {
        systemInstruction: systemInstruction,
        tools: [{ googleSearch: {} }],
        temperature: 0.1,
      },
    });

    let resultText = response.text || "";
    const firstBrace = resultText.indexOf('{');
    const lastBrace = resultText.lastIndexOf('}');

    if (firstBrace === -1 || lastBrace === -1) {
      throw new Error("Risposta del server non valida.");
    }

    const jsonStr = resultText.substring(firstBrace, lastBrace + 1).trim();
    const parsedData = JSON.parse(jsonStr);

    const sources: Array<{title: string, uri: string}> = [];
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (groundingChunks) {
      groundingChunks.forEach((chunk: any) => {
        if (chunk.web) {
          sources.push({ title: chunk.web.title || "Info", uri: chunk.web.uri });
        }
      });
    }

    return {
      ...parsedData,
      sources: sources.filter((v, i, a) => a.findIndex(t => (t.uri === v.uri)) === i).slice(0, 4)
    };
  } catch (error: any) {
    console.error("Gemini Error:", error);
    throw new Error("Errore nel recupero dati. Verifica i nomi dei comuni e riprova.");
  }
};

