import React from 'react';

interface RouteMapProps {
  origin: string;
  destination: string;
}

const RouteMap: React.FC<RouteMapProps> = ({ origin, destination }) => {
  // Funzione per pulire e potenziare la query di ricerca
  const formatMapQuery = (place: string) => {
    // Se il nome contiene già la provincia (es. "Altilia, Cosenza"), lo usiamo così
    // Altrimenti aggiungiamo Calabria per sicurezza.
    let query = place;
    if (!query.toLowerCase().includes('calabria')) {
      query += ", Calabria, Italia";
    }
    return encodeURIComponent(query);
  };

  const originQuery = formatMapQuery(origin);
  const destQuery = formatMapQuery(destination);

  // Utilizziamo il parametro saddr e daddr per definire univocamente partenza e arrivo
  const mapUrl = `https://maps.google.com/maps?saddr=${originQuery}&daddr=${destQuery}&output=embed&hl=it`;

  return (
    <div className="bg-white rounded-3xl shadow-xl border border-gray-100 overflow-hidden">
      <div className="bg-slate-800 p-4 text-white flex items-center justify-between">
        <div className="flex items-center gap-2">
          <i className="fa-solid fa-map-location-dot"></i>
          <span className="font-bold uppercase tracking-wider text-xs">Visualizzazione Percorso</span>
        </div>
        <div className="flex gap-2">
          <span className="bg-blue-500/20 text-blue-200 text-[10px] px-2 py-0.5 rounded-full border border-blue-500/30 font-bold uppercase">Mappa Regionale</span>
        </div>
      </div>
      <div className="aspect-video w-full relative bg-gray-100">
        <iframe
          width="100%"
          height="100%"
          style={{ border: 0 }}
          loading="lazy"
          src={mapUrl}
          title={`Percorso da ${origin} a ${destination}`}
          allowFullScreen
        ></iframe>

        <div className="absolute inset-0 pointer-events-none shadow-[inset_0_0_40px_rgba(0,0,0,0.05)]"></div>
      </div>
      <div className="p-3 bg-gray-50 border-t border-gray-100 flex items-center justify-center gap-2 text-[10px] text-gray-500 italic">
        <i className="fa-solid fa-circle-info"></i>
        Verifica sempre le indicazioni stradali locali. Percorso calcolato per: <strong>{destination}</strong>.
      </div>
    </div>
  );
};

