import { GoogleGenAI } from "@google/genai";
import { SearchParams, JourneyInfo } from "../types";

export const getTravelData = async (params: SearchParams, userCoords?: { lat: number; lng: number }): Promise<JourneyInfo> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const modelName = "gemini-3-pro-preview";

  const systemInstruction = `Sei un assistente esperto di logistica e trasporti per la regione Calabria.
Il tuo compito è fornire dati precisi su viaggi tra comuni calabresi.
DEVI RESTITUIRE ESCLUSIVAMENTE UN OGGETTO JSON.

REGOLE CRITICHE PER LA PRECISIONE:
1. DISAMBIGUAZIONE GEOGRAFICA: È fondamentale distinguere i comuni. 
   - Esempio: "Altilia" (o Altilia Grimaldi) è in PROVINCIA DI COSENZA (CS). Non confonderla mai con frazioni omonime nel crotonese.
2. NOMI LOCALITÀ NEL JSON: I campi "origin" e "destination" devono includere il nome del comune e la provincia (es. "Altilia, Cosenza" o "Catanzaro, Catanzaro"). Questo è essenziale per il corretto funzionamento delle mappe.
3. DATA E ORARIO: Considera la data di partenza per fornire previsioni meteo accurate per quel giorno specifico.
4. DISTANZA/DURATA AUTO: Calcola il percorso stradale reale (es. via A2 del Mediterraneo per Cosenza-Altilia).
5. METEO: Previsioni precise per la destinazione all'orario di arrivo stimato per il giorno richiesto.
6. TRENI: Identifica la stazione ferroviaria più vicina e verifica orari reali per il giorno specificato.
7. FORMATO: Restituisci SOLO il JSON senza markdown o commenti.

STRUTTURA JSON:
{
  "origin": "string (Comune, Provincia)",
  "destination": "string (Comune, Provincia)",
  "distance": "string",
  "duration": "string",
  "departureTime": "string (HH:MM)",
  "departureDate": "string (YYYY-MM-DD)",
  "arrivalTime": "string (HH:MM)",
  "weatherAtArrival": {
    "temp": "string",
    "condition": "string",
    "description": "string",
    "icon": "string (es. fa-sun)"
  },
  "trainAlternative": {
    "available": boolean,
    "departureStation": "string",
    "arrivalStation": "string",
    "options": [
      { "departureTime": "HH:MM", "arrivalTime": "HH:MM", "duration": "string", "changes": number }
    ],
    "description": "string",
    "note": "string"
  }
}`;

  const userPrompt = `Calcola viaggio in Calabria per il giorno ${params.departureDate}: da "${params.origin}" a "${params.destination}" partendo alle ${params.departureTime}. 
  ASSICURATI che se l'origine è "Altilia" o "Altilia Grimaldi", venga considerata quella in provincia di COSENZA.
  Trova tramite ricerca web: distanza stradale, meteo previsto all'arrivo per il giorno ${params.departureDate} e opzioni treno aggiornate.`;

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: userPrompt,
      config: {
        systemInstruction: systemInstruction,
        tools: [{ googleSearch: {} }],
        temperature: 0.1,
      },
    });

    let resultText = response.text || "";
    const firstBrace = resultText.indexOf('{');
    const lastBrace = resultText.lastIndexOf('}');

    if (firstBrace === -1 || lastBrace === -1) {
      throw new Error("Risposta del server non valida.");
    }

    const jsonStr = resultText.substring(firstBrace, lastBrace + 1).trim();
    const parsedData = JSON.parse(jsonStr);

    const sources: Array<{title: string, uri: string}> = [];
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (groundingChunks) {
      groundingChunks.forEach((chunk: any) => {
        if (chunk.web) {
          sources.push({ title: chunk.web.title || "Info", uri: chunk.web.uri });
        }
      });
    }

    return {
      ...parsedData,
      sources: sources.filter((v, i, a) => a.findIndex(t => (t.uri === v.uri)) === i).slice(0, 4)
    };
  } catch (error: any) {
    console.error("Gemini Error:", error);
    throw new Error("Errore nel recupero dati. Verifica i nomi dei comuni e riprova.");
  }
};

