  const destFull = `${params.destinationStreet} ${params.destinationNumber}, ${params.destinationCity}`.trim();

  const systemInstruction = `Sei un esperto di viaggi e logistica in Calabria.
Calcola dati precisi per un viaggio porta a porta.
DEVI RESTITUIRE ESCLUSIVAMENTE UN OGGETTO JSON.

REGOLE CRITICHE:
1. INDIRIZZI: Usa l'indirizzo specifico fornito (Via e Numero Civico) per calcolare la distanza e il tempo esatto.
2. DISAMBIGUAZIONE: Se la destinazione è Altilia, intendi "Altilia Grimaldi" in provincia di COSENZA.
3. NOMI NEL JSON: I campi "origin" e "destination" devono contenere l'indirizzo completo formattato: "Via/Piazza, Numero, Città, Provincia".
4. TRENI: Trova la stazione ferroviaria più vicina all'indirizzo di partenza specificato.
5. METEO: Previsioni per la destinazione il giorno ${params.departureDate}.

STRUTTURA JSON:
{
  "origin": "string (Via, N., Città, PR)",
  "destination": "string (Via, N., Città, PR)",
  "distance": "string",
  "duration": "string",
  "departureTime": "string (HH:MM)",
  "departureDate": "string",
  "arrivalTime": "string (HH:MM)",
  "weatherAtArrival": {
    "temp": "string",
    "condition": "string",
    "description": "string",
    "icon": "string (fa-icon)"
  },
  "trainAlternative": {
    "available": boolean,
    "departureStation": "string",
    "arrivalStation": "string",
    "options": [
      { "departureTime": "HH:MM", "arrivalTime": "HH:MM", "duration": "string", "changes": number }
    ],
    "note": "string"
  }
}`;

  const userPrompt = `Calcola viaggio in Calabria per il giorno ${params.departureDate}: 
  PARTENZA: ${originFull}
  DESTINAZIONE: ${destFull}
  ORARIO: ${params.departureTime}.
  Includi distanza stradale reale, meteo all'arrivo e opzioni ferroviarie dalla stazione più vicina all'indirizzo di partenza.`;

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: userPrompt,
      config: {
        systemInstruction: systemInstruction,
        tools: [{ googleSearch: {} }],
        temperature: 0.1,
      },
    });

    let resultText = response.text || "";
    const firstBrace = resultText.indexOf('{');
    const lastBrace = resultText.lastIndexOf('}');
    const jsonStr = resultText.substring(firstBrace, lastBrace + 1).trim();
    const parsedData = JSON.parse(jsonStr);

    const sources: Array<{title: string, uri: string}> = [];
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (groundingChunks) {
      groundingChunks.forEach((chunk: any) => {
        if (chunk.web) sources.push({ title: chunk.web.title || "Info", uri: chunk.web.uri });
      });
    }

    return {
      ...parsedData,
      sources: sources.filter((v, i, a) => a.findIndex(t => (t.uri === v.uri)) === i).slice(0, 4)
    };
  } catch (error) {
    console.error(error);
    throw new Error("Errore durante la ricerca. Verifica gli indirizzi e riprova.");
  }
};

