import React from 'react';

interface RouteMapProps {
  origin: string;
  destination: string;
}

const RouteMap: React.FC<RouteMapProps> = ({ origin, destination }) => {
  // Funzione per ottimizzare la stringa di ricerca per l'iframe di Google Maps
  const formatMapQuery = (place: string) => {
    let query = place.trim();

    // Rimuoviamo eventuali doppioni se Gemini ha già aggiunto Calabria, Italia
    // ma assicuriamoci che sia presente per evitare che Maps vada fuori regione
    if (!query.toLowerCase().includes('calabria')) {
      query += ", Calabria, Italia";
    }

    // Pulizia caratteri speciali superflui
    return encodeURIComponent(query);
  };

  const originQuery = formatMapQuery(origin);
  const destQuery = formatMapQuery(destination);

  // Utilizziamo saddr (start address) e daddr (destination address)
  // Aggiungiamo 't=m' per la mappa stradale standard e 'z=12' per uno zoom adeguato
  const mapUrl = `https://maps.google.com/maps?saddr=${originQuery}&daddr=${destQuery}&t=m&z=10&output=embed&hl=it`;

  return (
    <div className="bg-white rounded-3xl shadow-xl border border-gray-100 overflow-hidden">
      <div className="bg-slate-800 p-4 text-white flex items-center justify-between">
        <div className="flex items-center gap-2">
          <i className="fa-solid fa-map-location-dot"></i>
          <span className="font-bold uppercase tracking-wider text-xs">Itinerario Stradale</span>
        </div>
        <div className="flex gap-2">
          <span className="bg-emerald-500/20 text-emerald-200 text-[10px] px-2 py-0.5 rounded-full border border-emerald-500/30 font-bold uppercase tracking-tighter">Geolocalizzazione Calabria</span>
        </div>
      </div>
      <div className="aspect-video w-full relative bg-gray-100">
        <iframe
          width="100%"
          height="100%"
          style={{ border: 0 }}
          loading="lazy"
          src={mapUrl}
          title={`Viaggio da ${origin} a ${destination}`}
          allowFullScreen
        ></iframe>

        <div className="absolute inset-0 pointer-events-none shadow-[inset_0_0_40px_rgba(0,0,0,0.05)]"></div>
      </div>
      <div className="p-3 bg-gray-50 border-t border-gray-100 flex items-center justify-center gap-4 text-[10px] text-gray-500 italic">
        <div className="flex items-center gap-1">
          <i className="fa-solid fa-location-dot text-blue-500"></i>
          <span>Destinazione confermata in Calabria</span>
        </div>
        <div className="w-[1px] h-3 bg-gray-300"></div>
        <div className="flex items-center gap-1">
          <i className="fa-solid fa-circle-info"></i>
          <span>Verifica traffico locale in tempo reale</span>
        </div>
      </div>
    </div>
  );
};

