const JourneyForm: React.FC<JourneyFormProps> = ({ onSubmit, loading }) => {
  const [originCity, setOriginCity] = useState('');
  const [originStreet, setOriginStreet] = useState('');
  const [originNumber, setOriginNumber] = useState('');

  const [destinationCity, setDestinationCity] = useState('');
  const [destinationStreet, setDestinationStreet] = useState('');
  const [destinationNumber, setDestinationNumber] = useState('');

  const [departureTime, setDepartureTime] = useState(
    new Date().toLocaleTimeString('it-IT', { hour: '2-digit', minute: '2-digit' })
  );
  const [departureDate, setDepartureDate] = useState(
    new Date().toISOString().split('T')[0]
  );

  const [locating, setLocating] = useState(false);
  const [userCoords, setUserCoords] = useState<{ lat: number; lng: number } | undefined>();

  const flattenedCities = useMemo(() => {
    const list: string[] = [];
    Object.entries(CALABRIA_DATA).forEach(([province, cities]) => {
      cities.forEach(city => {
        list.push(`${city} (${province.split(' ')[0]})`);
      });
    });
    return list.sort();
  }, []);

  const handleGetLocation = () => {
    if (!navigator.geolocation) return;
    setLocating(true);
    navigator.geolocation.getCurrentPosition(
      (pos) => {
        setUserCoords({ lat: pos.coords.latitude, lng: pos.coords.longitude });
        setOriginCity("Posizione attuale");
        setOriginStreet("");
        setOriginNumber("");
        setLocating(false);
      },
      () => {
        setLocating(false);
        alert("Posizione non disponibile.");
      },
      { enableHighAccuracy: true, timeout: 5000 }
    );
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!originCity || !destinationCity) return;

    // Puliamo le città da eventuali province tra parentesi prima di inviare a Gemini
    const cleanOrigin = originCity.split(' (')[0];
    const cleanDest = destinationCity.split(' (')[0];

    onSubmit({ 
      originCity: cleanOrigin, originStreet, originNumber,
      destinationCity: cleanDest, destinationStreet, destinationNumber,
      departureTime, departureDate 
    }, userCoords);
  };

  return (
    <form onSubmit={handleSubmit} className="bg-white p-6 rounded-2xl shadow-xl border border-gray-100 max-w-4xl mx-auto -mt-12 relative z-10 space-y-8">

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Partenza */}
        <div className="space-y-4">
          <div className="flex justify-between items-center border-b border-gray-100 pb-2">
            <h3 className="text-sm font-bold text-blue-600 uppercase tracking-wider flex items-center gap-2">
              <i className="fa-solid fa-circle-dot"></i> Partenza
            </h3>
            <button 
              type="button" 
              onClick={handleGetLocation}
              className={`text-[10px] font-bold px-2 py-1 rounded transition-colors ${
                userCoords ? 'bg-emerald-100 text-emerald-700' : 'text-blue-600 hover:bg-blue-50 border border-blue-100'
              }`}
            >
              <i className={`fa-solid ${locating ? 'fa-spinner animate-spin' : 'fa-location-crosshairs'}`}></i>
              {userCoords ? ' POSIZIONE OK' : ' USA GPS'}
            </button>
          </div>
          <div className="space-y-3">
            <input
              list="cities-list"
              type="text"
              className="w-full px-4 py-3 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
              placeholder="Città (es. Cosenza)"
              value={originCity}
              onChange={(e) => setOriginCity(e.target.value)}
              required
            />
            <div className="flex gap-2">
              <input
                type="text"
                className="flex-[3] px-4 py-3 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                placeholder="Via o Piazza"
                value={originStreet}
                onChange={(e) => setOriginStreet(e.target.value)}
              />
              <input
                type="text"
                className="flex-1 px-4 py-3 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                placeholder="N."
                value={originNumber}
                onChange={(e) => setOriginNumber(e.target.value)}
              />
            </div>
          </div>
        </div>

        {/* Destinazione */}
        <div className="space-y-4">
          <div className="flex justify-between items-center border-b border-gray-100 pb-2">
            <h3 className="text-sm font-bold text-emerald-600 uppercase tracking-wider flex items-center gap-2">
              <i className="fa-solid fa-location-dot"></i> Destinazione
            </h3>
          </div>
          <div className="space-y-3">
            <input
              list="cities-list"
              type="text"
              className="w-full px-4 py-3 border border-gray-200 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none transition-all"
              placeholder="Destinazione (es. Altilia)"
              value={destinationCity}
              onChange={(e) => setDestinationCity(e.target.value)}
              required
            />
            <div className="flex gap-2">
              <input
                type="text"
                className="flex-[3] px-4 py-3 border border-gray-200 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none transition-all"
                placeholder="Via o Piazza"
                value={destinationStreet}
                onChange={(e) => setDestinationStreet(e.target.value)}
              />
              <input
                type="text"
                className="flex-1 px-4 py-3 border border-gray-200 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none transition-all"
                placeholder="N."
                value={destinationNumber}
                onChange={(e) => setDestinationNumber(e.target.value)}
              />
            </div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 border-t border-gray-100 pt-6">
        <div className="space-y-1">
          <label className="text-[10px] font-bold text-gray-400 uppercase ml-2">Giorno Viaggio</label>
          <input
            type="date"
            min={new Date().toISOString().split('T')[0]}
            className="w-full px-4 py-3 border border-gray-200 rounded-xl outline-none"
            value={departureDate}
            onChange={(e) => setDepartureDate(e.target.value)}
            required
          />
        </div>
        <div className="space-y-1">
          <label className="text-[10px] font-bold text-gray-400 uppercase ml-2">Orario Partenza</label>
          <input
            type="time"
            className="w-full px-4 py-3 border border-gray-200 rounded-xl outline-none"
            value={departureTime}
            onChange={(e) => setDepartureTime(e.target.value)}
            required
          />
        </div>
        <div className="flex items-end">
          <button
            type="submit"
            disabled={loading}
            className="w-full py-4 bg-gradient-to-r from-blue-600 to-blue-800 text-white rounded-xl font-bold shadow-lg hover:from-blue-700 hover:to-blue-900 transition-all flex items-center justify-center gap-2"
          >
            {loading ? <i className="fa-solid fa-circle-notch animate-spin"></i> : <i className="fa-solid fa-route"></i>}
            CALCOLA PERCORSO
          </button>
        </div>
      </div>

      <datalist id="cities-list">
        {flattenedCities.map(city => <option key={city} value={city} />)}
      </datalist>
    </form>
  );
};

export default JourneyForm;

import { GoogleGenAI, Type } from "@google/genai";
import { SearchParams, JourneyInfo } from "../types";

export const getTravelData = async (params: SearchParams, userCoords?: { lat: number; lng: number }): Promise<JourneyInfo> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const modelName = "gemini-3-flash-preview";

  const originFull = `${params.originStreet} ${params.originNumber}, ${params.originCity}`.trim();
  const destFull = `${params.destinationStreet} ${params.destinationNumber}, ${params.destinationCity}`.trim();

  // Definiamo lo schema per garantire che il JSON sia sempre corretto
  const responseSchema = {
    type: Type.OBJECT,
    properties: {
      origin: { type: Type.STRING },
      destination: { type: Type.STRING },
      distance: { type: Type.STRING },
      duration: { type: Type.STRING },
      departureTime: { type: Type.STRING },
      departureDate: { type: Type.STRING },
      arrivalTime: { type: Type.STRING },
      weatherAtDeparture: {
        type: Type.OBJECT,
        properties: {
          temp: { type: Type.STRING },
          condition: { type: Type.STRING },
          description: { type: Type.STRING },
          icon: { type: Type.STRING },
        },
        required: ["temp", "condition", "description", "icon"]
      },
      weatherAtArrival: {
        type: Type.OBJECT,
        properties: {
          temp: { type: Type.STRING },
          condition: { type: Type.STRING },
          description: { type: Type.STRING },
          icon: { type: Type.STRING },
        },
        required: ["temp", "condition", "description", "icon"]
      },
      trainAlternative: {
        type: Type.OBJECT,
        properties: {
          available: { type: Type.BOOLEAN },
          departureStation: { type: Type.STRING },
          arrivalStation: { type: Type.STRING },
          options: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                departureTime: { type: Type.STRING },
                arrivalTime: { type: Type.STRING },
                duration: { type: Type.STRING },
                changes: { type: Type.INTEGER }
              }
            }
          },
          note: { type: Type.STRING }
        }
      }
    },
    required: ["origin", "destination", "distance", "duration", "departureTime", "arrivalTime", "weatherAtDeparture", "weatherAtArrival"]
  };

  const systemInstruction = `Sei un assistente di viaggio per la Calabria. 
  Calcola distanza stradale, tempi di percorrenza e meteo per un viaggio il ${params.departureDate}.
  FONDAMENTALE: Assicurati che le località siano interpretate come comuni della Calabria (es. Altilia -> Altilia Grimaldi CS).
  Restituisci solo il JSON seguendo lo schema.`;

  const userPrompt = `Pianifica viaggio da ${originFull} a ${destFull} (Calabria) con partenza alle ${params.departureTime}.`;

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: userPrompt,
      config: {
        systemInstruction: systemInstruction,
        tools: [{ googleSearch: {} }],
        temperature: 0.1,
        responseMimeType: "application/json",
        responseSchema: responseSchema
      },
    });

    const text = response.text;
    if (!text) throw new Error("Risposta vuota dal modello.");

    const parsedData = JSON.parse(text);

    const sources: Array<{title: string, uri: string}> = [];
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (groundingChunks) {
      groundingChunks.forEach((chunk: any) => {
        if (chunk.web) sources.push({ title: chunk.web.title || "Info", uri: chunk.web.uri });
      });
    }

    return {
      ...parsedData,
      sources: sources.filter((v, i, a) => a.findIndex(t => (t.uri === v.uri)) === i).slice(0, 4)
    };
  } catch (error: any) {
    console.error("Gemini API Error:", error);

    // Gestione specifica Errore Quota (429)
    if (error.message?.includes("429") || error.message?.toLowerCase().includes("quota") || error.message?.toLowerCase().includes("limit")) {
      throw new Error("Quota giornaliera o limiti di velocità raggiunti. Attendi 60 secondi e riprova.");
    }

    if (error.message?.includes("JSON")) {
      throw new Error("Errore nell'elaborazione dei dati. Riprova tra un istante.");
    }

    throw new Error("Impossibile calcolare il percorso. Verifica la connessione o gli indirizzi inseriti.");
  }
};

import React, { useState } from 'react';
import Header from './components/Header';
import JourneyForm from './components/JourneyForm';
import JourneyResult from './components/JourneyResult';
import { getTravelData } from './services/geminiService';
import { JourneyInfo, SearchParams, AppStatus } from './types';

const App: React.FC = () => {
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [journeyData, setJourneyData] = useState<JourneyInfo | null>(null);
  const [errorMessage, setErrorMessage] = useState<string>('');

  const handleSearch = async (params: SearchParams, coords?: { lat: number; lng: number }) => {
    setStatus(AppStatus.LOADING);
    setErrorMessage('');

    try {
      const data = await getTravelData(params, coords);
      setJourneyData(data);
      setStatus(AppStatus.SUCCESS);
    } catch (err: any) {
      console.error(err);
      setErrorMessage(err.message || 'Si è verificato un errore imprevisto.');
      setStatus(AppStatus.ERROR);
    }
  };

  return (
    <div className="min-h-screen pb-20 bg-slate-50">
      <Header />

      <main className="container mx-auto px-4">
        <JourneyForm onSubmit={handleSearch} loading={status === AppStatus.LOADING} />

        {status === AppStatus.ERROR && (
          <div className="mt-12 max-w-2xl mx-auto bg-white border border-red-100 p-8 rounded-3xl shadow-xl animate-in zoom-in-95 duration-300">
            <div className="flex flex-col items-center text-center gap-4">
              <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center">
                <i className="fa-solid fa-hourglass-half text-red-500 text-2xl animate-pulse"></i>
              </div>
              <div>
                <h3 className="text-xl font-black text-gray-900 mb-2">Ops! Qualcosa è andato storto</h3>
                <p className="text-gray-600 leading-relaxed">{errorMessage}</p>
              </div>
              <button 
                onClick={() => setStatus(AppStatus.IDLE)}
                className="mt-4 px-8 py-3 bg-red-500 text-white rounded-xl font-bold hover:bg-red-600 transition-colors shadow-lg shadow-red-200"
              >
                Ho capito, riprovo
              </button>
            </div>
          </div>
        )}

        {status === AppStatus.IDLE && (
          <div className="mt-20 text-center text-gray-400 opacity-60 animate-in fade-in duration-700">
            <div className="text-6xl mb-4">
              <i className="fa-solid fa-map-location-dot"></i>
            </div>
            <p className="text-xl font-medium">Inserisci i luoghi per calcolare rotta e meteo</p>
            <p className="text-sm">Servizio ottimizzato per la regione Calabria</p>
          </div>
        )}

        {status === AppStatus.SUCCESS && journeyData && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            <JourneyResult info={journeyData} />
          </div>
        )}
      </main>

      <footer className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-md border-t border-gray-200 py-4 z-20">
        <div className="container mx-auto px-4 flex justify-between items-center text-gray-500 text-sm">
          <p>© 2024 Calabria Travel Explorer</p>
          <p className="flex items-center gap-2">
            Made for <span className="font-bold text-blue-600">Calabria</span> 
            <i className="fa-solid fa-heart text-red-500"></i>
          </p>
        </div>
      </footer>
    </div>
  );
};

export default App;
